4	function gitInfo() {
5	  try {
6	    const sha = execSync("git rev-parse --short HEAD", { encoding: "utf8" }).trim();
7	    const date = execSync("git log -1 --format=%cI", { encoding: "utf8" }).trim();
8	    return { sha, date };
9	  } catch {
10	    const sha = process.env.BUILD_SHA?.slice(0, 7) ?? "unknown";
11	    return { sha, date: new Date().toISOString() };
12	  }
13	}
