15	const { sha, date } = gitInfo();
16	
17	const nextConfig: NextConfig = {
18	  env: {
19	    NEXT_PUBLIC_BUILD_SHA: sha,
20	    NEXT_PUBLIC_BUILD_DATE: date,
21	  },
22	};
