34	function useActiveIssues() {
35	  const [issues, setIssues] = useState<ActiveIssue[]>([]);
36	  const [loading, setLoading] = useState(true);
37	
38	  useEffect(() => {
39	    const supabase = createClient();
40	    supabase
41	      .from("issues")
42	      .select("id, title, severity, status, summary, affected_nas, updated_at")
43	      .not("status", "in", "(resolved,cancelled)")
44	      .order("updated_at", { ascending: false })
45	      .limit(20)
46	      .then(({ data }) => {
47	        setIssues((data ?? []) as ActiveIssue[]);
48	        setLoading(false);
49	      });
50	  }, []);
51	
52	  return { issues, loading };
53	}
