3	import { useEffect, useState } from "react";
4	import { createClient } from "@/lib/supabase/client";
5	import type { NasUnit } from "@synology-monitor/shared";
6	
7	export function useNasUnits() {
8	  const [units, setUnits] = useState<NasUnit[]>([]);
9	  const [loading, setLoading] = useState(true);
10	
11	  useEffect(() => {
12	    const supabase = createClient();
13	
14	    async function fetch() {
15	      const { data, error } = await supabase
16	        .from("nas_units")
17	        .select("*")
18	        .order("name");
19	
20	      if (!error && data) {
21	        setUnits(data as NasUnit[]);
22	      }
23	      setLoading(false);
24	    }
25	
26	    fetch();
27	
28	    // Subscribe to status changes
29	    const channel = supabase
30	      .channel("smon-nas-units")
31	      .on(
32	        "postgres_changes",
33	        { event: "*", schema: "public", table: "nas_units" },
34	        (payload) => {
35	          if (payload.eventType === "UPDATE") {
36	            setUnits((prev) =>
37	              prev.map((u) =>
38	                u.id === (payload.new as NasUnit).id
39	                  ? (payload.new as NasUnit)
40	                  : u
41	              )
42	            );
43	          }
44	        }
45	      )
46	      .subscribe();
47	
48	    return () => {
49	      supabase.removeChannel(channel);
50	    };
51	  }, []);
52	
53	  return { units, loading };
54	}
