1	"use client";
2	
3	import { useEffect, useState, useCallback, useRef } from "react";
4	import { createClient } from "@/lib/supabase/client";
5	
6	interface MetricDataPoint {
7	  recorded_at: string;
8	  value: number;
9	}
10	
11	interface MetricSeries {
12	  type: string;
13	  unit: string;
14	  data: MetricDataPoint[];
15	}
16	
17	export function useMetrics(
18	  nasId: string | null,
19	  types: string[],
20	  range: "1h" | "6h" | "24h" | "7d" | "30d" = "24h"
21	) {
22	  const [series, setSeries] = useState<MetricSeries[]>([]);
23	  const [loading, setLoading] = useState(true);
24	
25	  // Memoize types to prevent infinite re-render loop
26	  const typesKey = types.join(",");
27	  const typesRef = useRef(typesKey);
28	  if (typesKey !== typesRef.current) {
29	    typesRef.current = typesKey;
30	  }
31	
32	  const fetchMetrics = useCallback(async () => {
33	    if (!nasId) return;
34	
35	    const supabase = createClient();
36	    const from = new Date(
37	      Date.now() - parseRange(range)
38	    ).toISOString();
39	
40	    const results: MetricSeries[] = [];
41	
42	    for (const type of typesRef.current.split(",")) {
43	      const { data, error } = await supabase
44	        .from("metrics")
45	        .select("recorded_at, value, unit")
46	        .eq("nas_id", nasId)
47	        .eq("type", type)
48	        .gte("recorded_at", from)
49	        .order("recorded_at", { ascending: true })
50	        .limit(500);
51	
52	      if (!error && data && data.length > 0) {
53	        results.push({
54	          type,
55	          unit: data[0].unit,
56	          data: data.map((d) => ({
57	            recorded_at: d.recorded_at,
58	            value: d.value,
59	          })),
60	        });
61	      }
62	    }
63	
64	    setSeries(results);
65	    setLoading(false);
66	  }, [nasId, range]); // Only depend on nasId and range, not types
67	
68	  useEffect(() => {
69	    fetchMetrics();
70	    const interval = setInterval(fetchMetrics, 30000); // Poll every 30s
71	    return () => clearInterval(interval);
72	  }, [fetchMetrics]);
73	
74	  return { series, loading, refresh: fetchMetrics };
75	}
76	
77	function parseRange(range: string): number {
78	  switch (range) {
79	    case "1h": return 60 * 60 * 1000;
80	    case "6h": return 6 * 60 * 60 * 1000;
81	    case "24h": return 24 * 60 * 60 * 1000;
82	    case "7d": return 7 * 24 * 60 * 60 * 1000;
83	    case "30d": return 30 * 24 * 60 * 60 * 1000;
84	    default: return 24 * 60 * 60 * 1000;
85	  }
86	}
