1	import { NextResponse } from "next/server";
2	import { createClient as createSupabaseServerClient } from "@/lib/supabase/server";
3	import { getNasApiConfigs } from "@/lib/server/nas-api-client";
4	
5	export const runtime = "nodejs";
6	export const dynamic = "force-dynamic";
7	
8	/**
9	 * NAS reachability probe (PLAN.md §7) — drives the dashboard's Offline-Mode
10	 * indicator. Pings each configured nas-api /health over Tailscale; when a NAS is
11	 * unreachable the UI disables live-action controls and shows an offline badge,
12	 * so operators aren't left clicking actions that will fail. Read-only views and
13	 * fetch_evidence-backed diagnosis stay available regardless.
14	 */
15	export async function GET() {
16	  const supabase = await createSupabaseServerClient();
17	  const {
18	    data: { user },
19	  } = await supabase.auth.getUser();
20	  if (!user) {
21	    return NextResponse.json({ error: "Authentication required." }, { status: 401 });
22	  }
23	
24	  const configs = getNasApiConfigs();
25	  const results = await Promise.all(
26	    configs.map(async (config) => {
27	      try {
28	        const res = await fetch(`${config.url}/health`, {
29	          headers: { Authorization: `Bearer ${config.apiSecret}` },
30	          signal: AbortSignal.timeout(5_000),
31	        });
32	        return { name: config.name, reachable: res.ok };
33	      } catch {
34	        return { name: config.name, reachable: false };
35	      }
36	    }),
37	  );
38	
39	  return NextResponse.json({
40	    configured: configs.length,
41	    units: results,
42	    anyOffline: results.some((r) => !r.reachable),
43	    allOffline: configs.length > 0 && results.every((r) => !r.reachable),
44	  });
45	}
