1	/**
2	 * HTTP client for the NAS API (three-tier shell execution service).
3	 * The NAS API runs as a Docker container on each Synology NAS and accepts
4	 * bearer-authenticated POST requests to execute shell commands.
5	 *
6	 * Tier 1 — read-only, auto-executes.
7	 * Tier 2 — service ops (docker/synopkg restarts), requires approval token.
8	 * Tier 3 — file ops touching /volume*, requires approval token.
9	 */
10	
11	import { createHmac } from "node:crypto";
12	import type { NasTarget } from "@/lib/server/tools";
13	
14	export interface NasApiConfig {
15	  /** Logical NAS name used in issue.affected_nas (e.g. "edgesynology1") */
16	  name: string;
17	  /** Base URL of the nas-api container, e.g. "http://192.168.1.100:7734" */
18	  url: string;
19	  /** Bearer token — must match NAS_API_SECRET on the NAS */
20	  apiSecret: string;
21	  /** HMAC key for approval tokens — must match NAS_API_APPROVAL_SIGNING_KEY on the NAS */
22	  approvalSigningKey: string;
23	}
24	
25	export interface NasApiExecResult {
26	  stdout: string;
27	  stderr: string;
28	  exit_code: number;
29	  duration_ms: number;
30	  timed_out?: boolean;
31	}
32	
33	export interface NasApiPreviewResult {
34	  tier: number;   // -1=blocked, 1=read, 2=service, 3=file
35	  summary: string;
36	  blocked: boolean;
37	}
38	
39	export interface NasCommandResult {
40	  stdout: string;
41	  stderr: string;
42	  exitCode: number;
43	}
44	
45	/** Reads NAS API configs from environment variables. */
46	export function getNasApiConfigs(): NasApiConfig[] {
47	  const slots: Array<{ name: string; prefix: string }> = [
48	    { name: "edgesynology1", prefix: "NAS_EDGE1" },
49	    { name: "edgesynology2", prefix: "NAS_EDGE2" },
50	  ];
51	
52	  return slots
53	    .map(({ name, prefix }) => ({
54	      name,
55	      url: process.env[`${prefix}_API_URL`] ?? "",
56	      apiSecret: process.env[`${prefix}_API_SECRET`] ?? "",
57	      approvalSigningKey: process.env[`${prefix}_API_SIGNING_KEY`] ?? "",
58	    }))
59	    .filter((c) => c.url && c.apiSecret);
60	}
61	
62	/**
63	 * Resolves the NAS API config for a given NAS name (or alias).
64	 * Returns null if no config is available for that NAS.
65	 */
66	export function resolveNasApiConfig(nasName: string): NasApiConfig | null {
67	  return (
68	    getNasApiConfigs().find(
69	      (c) => c.name === nasName || nasName.includes(c.name) || c.name.includes(nasName),
70	    ) ?? null
71	  );
72	}
73	
74	/**
75	 * Builds a base64url-encoded HMAC-signed approval token for a Tier 2/3 command.
76	 * The token is verified by the NAS API before executing the command.
77	 *
78	 * Token format mirrors auth.go ApprovalToken:
79	 *   { command, tier, expires_at, signature }
80	 * Signature = HMAC-SHA256(approvalSigningKey, command + "\n" + expires_at)
81	 */
82	export function buildNasApiApprovalToken(
83	  config: NasApiConfig,
84	  command: string,
85	  tier: 2 | 3,
86	): string {
87	  const expiresAt = new Date(Date.now() + 15 * 60_000).toISOString();
88	  const signature = createHmac("sha256", config.approvalSigningKey)
89	    .update(`${command}\n${expiresAt}`)
90	    .digest("hex");
91	
92	  const token = { command, tier, expires_at: expiresAt, signature };
93	  return Buffer.from(JSON.stringify(token)).toString("base64url");
94	}
95	
96	/**
97	 * Calls POST /exec on the NAS API.
98	 * For Tier 1 commands the approval token is not required.
99	 * For Tier 2/3 commands pass the token returned by buildNasApiApprovalToken.
100	 */
101	export async function nasApiExec(
102	  config: NasApiConfig,
103	  command: string,
104	  tier: 1 | 2 | 3,
105	  approvalToken?: string,
106	  timeoutMs = 30_000,
107	): Promise<NasApiExecResult> {
108	  const body: Record<string, unknown> = { command, tier, timeout_ms: timeoutMs };
109	  if (approvalToken) body.approval_token = approvalToken;
110	
111	  const response = await fetch(`${config.url}/exec`, {
112	    method: "POST",
113	    headers: {
114	      "Content-Type": "application/json",
115	      Authorization: `Bearer ${config.apiSecret}`,
116	    },
117	    body: JSON.stringify(body),
118	    signal: AbortSignal.timeout(timeoutMs + 8_000),
119	  });
120	
121	  if (!response.ok) {
122	    const err = await response.json().catch(() => ({ error: response.statusText })) as { error?: string };
123	    throw new Error(`NAS API /exec error ${response.status}: ${err.error ?? response.statusText}`);
124	  }
125	
126	  return response.json() as Promise<NasApiExecResult>;
127	}
128	
129	/**
130	 * Calls POST /preview on the NAS API — classifies a command's tier
131	 * without executing it. Used to build the operator approval prompt.
132	 */
133	export async function nasApiPreview(
134	  config: NasApiConfig,
135	  command: string,
136	): Promise<NasApiPreviewResult> {
137	  const response = await fetch(`${config.url}/preview`, {
138	    method: "POST",
139	    headers: {
140	      "Content-Type": "application/json",
141	      Authorization: `Bearer ${config.apiSecret}`,
142	    },
143	    body: JSON.stringify({ command }),
144	    signal: AbortSignal.timeout(10_000),
145	  });
146	
147	  if (!response.ok) {
148	    const err = await response.json().catch(() => ({ error: response.statusText })) as { error?: string };
149	    throw new Error(`NAS API /preview error ${response.status}: ${err.error ?? response.statusText}`);
150	  }
151	
152	  return response.json() as Promise<NasApiPreviewResult>;
153	}
154	
155	export async function executeNasCommand(
156	  target: NasTarget,
157	  command: string,
158	  timeoutMs = 90_000,
159	): Promise<NasCommandResult> {
160	  const config = resolveNasApiConfig(target);
161	  if (!config) {
162	    throw new Error(`NAS API config is missing for target: ${target}`);
163	  }
164	
165	  const preview = await nasApiPreview(config, command);
166	  if (preview.blocked || preview.tier < 1 || preview.tier > 3) {
167	    throw new Error(`Command is blocked by NAS API validation: ${preview.summary}`);
168	  }
169	
170	  const tier = preview.tier as 1 | 2 | 3;
171	  let approvalToken: string | undefined;
172	  if (tier === 2 || tier === 3) {
173	    approvalToken = buildNasApiApprovalToken(config, command, tier);
174	  }
175	
176	  const result = await nasApiExec(config, command, tier, approvalToken, timeoutMs);
177	  return {
178	    stdout: result.stdout.trim(),
179	    stderr: result.stderr.trim(),
180	    exitCode: result.exit_code,
181	  };
182	}
183	
184	export async function collectNasDiagnostics(lookbackHours = 2) {
185	  const configs = getNasApiConfigs();
186	  const driveLines = Math.max(60, Math.min(300, lookbackHours * 50));
187	  const shareSyncLines = Math.max(40, Math.min(240, lookbackHours * 30));
188	  const command = [
189	    "set -e",
190	    "echo '## hostname'",
191	    "hostname",
192	    "echo '## uptime'",
193	    "uptime",
194	    "echo '## volume1'",
195	    "df -h /volume1 2>/dev/null || true",
196	    "echo '## agent'",
197	    "/usr/local/bin/docker ps --format '{{.Image}}|{{.Status}}|{{.Names}}' | grep synology-monitor-agent || true",
198	    "echo '## drive_log'",
199	    `tail -n ${driveLines} /var/log/synologydrive.log 2>/dev/null || true`,
200	    "echo '## sharesync_log'",
201	    `for f in /volume1/*/@synologydrive/log/syncfolder.log; do [ -f "$f" ] || continue; echo "$f"; tail -n ${shareSyncLines} "$f"; done 2>/dev/null || true`,
202	  ].join("\n");
203	
204	  return Promise.all(
205	    configs.map(async (config) => {
206	      try {
207	        const result = await nasApiExec(config, command, 1, undefined, 30_000);
208	        return {
209	          target: config.name,
210	          ok: result.exit_code === 0,
211	          stdout: result.stdout.trim(),
212	          stderr: result.stderr.trim(),
213	        };
214	      } catch (error) {
215	        return {
216	          target: config.name,
217	          ok: false,
218	          stdout: "",
219	          stderr: error instanceof Error ? error.message : "Unknown NAS API error",
220	        };
221	      }
222	    }),
223	  );
224	}
