250	function aggregateDevicePoints(devices: DiskIODevice[]): { time: number; read_bps: number; write_bps: number }[] {
251	  const byTime = new Map<number, { time: number; read_bps: number; write_bps: number }>();
252	
253	  for (const dev of devices) {
254	    for (const pt of dev.points) {
255	      const bucket = Math.round(pt.time / 15000) * 15000;
256	      const existing = byTime.get(bucket);
257	      if (existing) {
258	        existing.read_bps += pt.read_bps;
259	        existing.write_bps += pt.write_bps;
260	      } else {
261	        byTime.set(bucket, { time: bucket, read_bps: pt.read_bps, write_bps: pt.write_bps });
262	      }
263	    }
264	  }
265	
266	  return Array.from(byTime.values()).sort((a, b) => a.time - b.time);
