4	export async function updateSession(request: NextRequest) {
5	  if (request.nextUrl.pathname.startsWith("/api/internal/issue-worker/")) {
6	    return NextResponse.next({ request });
7	  }
8	
9	  let supabaseResponse = NextResponse.next({ request });
10	
11	  const supabase = createServerClient(
12	    process.env.NEXT_PUBLIC_SUPABASE_URL!,
13	    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
14	    {
15	      cookies: {
16	        getAll() {
17	          return request.cookies.getAll();
18	        },
19	        setAll(cookiesToSet: { name: string; value: string; options?: Record<string, unknown> }[]) {
20	          cookiesToSet.forEach(({ name, value }) =>
21	            request.cookies.set(name, value)
22	          );
23	          supabaseResponse = NextResponse.next({ request });
24	          cookiesToSet.forEach(({ name, value, options }) =>
25	            supabaseResponse.cookies.set(name, value, options as any)
26	          );
27	        },
28	      },
29	    }
30	  );
31	
32	  const {
33	    data: { user },
34	  } = await supabase.auth.getUser();
35	
36	  if (
37	    !user &&
38	    !request.nextUrl.pathname.startsWith("/login") &&
39	    !request.nextUrl.pathname.startsWith("/auth")
40	  ) {
41	    const url = request.nextUrl.clone();
42	    url.pathname = "/login";
43	    return NextResponse.redirect(url);
44	  }
45	
46	  return supabaseResponse;
47	}
