8	export function formatBytes(bytes: number): string {
9	  if (bytes === 0) return "0 B";
10	  const k = 1024;
11	  const sizes = ["B", "KB", "MB", "GB", "TB", "PB"];
12	  const i = Math.floor(Math.log(bytes) / Math.log(k));
13	  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
