21	 * Format a date to America/New_York timezone (EST/EDT)
22	 * Example: "Apr 1, 3:15 PM"
23	 */
24	export function formatET(dateInput: string | Date): string {
25	  const date = typeof dateInput === "string" ? new Date(dateInput) : dateInput;
26	  return date.toLocaleString("en-US", {
27	    timeZone: "America/New_York",
28	    month: "short",
29	    day: "numeric",
30	    hour: "numeric",
31	    minute: "2-digit",
32	    hour12: true,
33	  });
34	}
