36	/**
37	 * Format a date to full America/New_York timezone with date
38	 * Example: "Apr 1, 2026 at 3:15 PM"
39	 */
40	export function formatETFull(dateInput: string | Date): string {
41	  const date = typeof dateInput === "string" ? new Date(dateInput) : dateInput;
42	  return date.toLocaleString("en-US", {
43	    timeZone: "America/New_York",
44	    month: "short",
45	    day: "numeric",
46	    year: "numeric",
47	    hour: "numeric",
48	    minute: "2-digit",
49	    hour12: true,
50	  });
51	}
