53	/**
54	 * Relative time with ET absolute time appended
55	 * Example: "2h ago (3:15 PM ET)"
56	 */
57	export function timeAgoET(dateInput: string | Date): string {
58	  const date = typeof dateInput === "string" ? new Date(dateInput) : dateInput;
59	  const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
60	
61	  let relative: string;
62	  if (seconds < 60) relative = `${seconds}s ago`;
63	  else if (seconds < 3600) relative = `${Math.floor(seconds / 60)}m ago`;
64	  else if (seconds < 86400) relative = `${Math.floor(seconds / 3600)}h ago`;
65	  else if (seconds < 604800) relative = `${Math.floor(seconds / 86400)}d ago`;
66	  else {
67	    // More than 7 days - show full date instead of relative
68	    return formatETFull(dateInput);
69	  }
70	
71	  return `${relative} (${formatET(dateInput)} ET)`;
72	}
