74	/**
75	 * Keep original timeAgo for backward compatibility
76	 */
77	export function timeAgo(date: string): string {
78	  const seconds = Math.floor(
79	    (Date.now() - new Date(date).getTime()) / 1000
80	  );
81	
82	  if (seconds < 60) return `${seconds}s ago`;
83	  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
84	  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`;
85	  return `${Math.floor(seconds / 86400)}d ago`;
86	}
