36	export async function POST(request: Request) {
37	  try {
38	    const supabase = await createSupabaseServerClient();
39	    const {
40	      data: { user },
41	    } = await supabase.auth.getUser();
42	
43	    if (!user) {
44	      return NextResponse.json({ error: "Authentication required." }, { status: 401 });
45	    }
46	
47	    const body = await request.json();
48	    const { key, value } = body;
49	
50	    if (!key || !value || typeof key !== "string" || typeof value !== "string") {
51	      return NextResponse.json({ error: "key and value are required strings." }, { status: 400 });
52	    }
53	
54	    const allowedKeys = [
55	      // 3-stage pipeline config (PLAN.md §8.2): stage_{structurer,reasoning,explainer}_{model,effort}
56	      ...STAGE_SETTING_KEYS,
57	      // Non-issue-agent feature models still in use (copilot, minimax, clustering,
58	      // second-opinion). The legacy 7-stage keys were removed with the old pipeline.
59	      "diagnosis_model",
60	      "remediation_model",
61	      "second_opinion_model",
62	      "cluster_model",
63	    ];
64	    if (!allowedKeys.includes(key)) {
65	      return NextResponse.json({ error: `Invalid setting key. Allowed: ${allowedKeys.join(", ")}` }, { status: 400 });
66	    }
67	
68	    // Effort keys carry an abstract level, not a model id — validate against the matrix (§8.3).
69	    if (key.endsWith("_effort") && !isEffortLevel(value.trim())) {
70	      return NextResponse.json(
71	        { error: "Invalid effort level. Allowed: minimal, low, medium, high." },
72	        { status: 400 },
73	      );
74	    }
75	
76	    const { error } = await supabase.from("ai_settings").upsert(
77	      { key, value: value.trim(), updated_at: new Date().toISOString() },
78	      { onConflict: "key" },
79	    );
80	
81	    if (error) throw error;
82	
83	    clearAiSettingsCache();
84	    return NextResponse.json({ ok: true });
85	  } catch (error) {
86	    return NextResponse.json(
87	      { error: error instanceof Error ? error.message : "Failed to save setting." },
