**Complete real example from the codebase (storage page):**  
File: `/worksp/monitor/app/apps/web/src/app/(dashboard)/storage/page.tsx` (lines 1–174)

```tsx
"use client";  // ← Required: This is a CLIENT COMPONENT (uses hooks, Supabase browser client)

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { formatBytes, cn } from "@/lib/utils";
import { HardDrive, Thermometer } from "lucide-react";

interface StorageData {
