### 3. **Data Fetching & Backend Calls: Three Paths Explained**

The web app uses **three distinct paths** to reach backend data:

#### **Path A: Supabase Direct (Browser Client)**
Used for read-only data retrieval and subscriptions from frontend.

```tsx
// File: /worksp/monitor/app/apps/web/src/lib/supabase/client.ts
import { createBrowserClient } from "@supabase/ssr";

export function createClient() {
  return createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  );
}

// Usage example from /worksp/monitor/app/apps/web/src/hooks/use-nas-units.ts (lines 7-54):
export function useNasUnits() {
  const [units, setUnits] = useState<NasUnit[]>([]);

  useEffect(() => {
    const supabase = createClient();

    // Read-only query
    const { data, error } = await supabase
      .from("nas_units")
      .select("*")
      .order("name");

    if (!error && data) setUnits(data as NasUnit[]);

    // Real-time subscription via Postgres Changes
    const channel = supabase
      .channel("smon-nas-units")
      .on("postgres_changes", 
        { event: "*", schema: "public", table: "nas_units" },
        (payload) => {
          if (payload.eventType === "UPDATE") {
            setUnits(prev => prev.map(u => 
              u.id === payload.new.id ? payload.new : u
            ));
          }
        }
      )
      .subscribe();

    return () => supabase.removeChannel(channel);
  }, []);

  return { units };
}
```

**Key tables accessed directly from Supabase (browser):**
- `nas_units` — NAS inventory
- `metrics` — Time-series metrics (CPU, memory, network, disk I/O)
- `storage_snapshots` — Volume/disk capacity & health
- `nas_logs` — Aggregated logs
- `container_status` — Docker container state
- `disk_io_stats` — Disk I/O performance data
- `process_snapshots` — Top processes
- `container_io` — Container I/O performance
- `issues` — AI-detected issues
- `ai_settings` — Configuration

---

#### **Path B: Next.js API Routes (Server-side)**
Used for operations that need **authentication checks, Supabase writes, or calls to the NAS API**.

**Example route:** `/worksp/monitor/app/apps/web/src/app/api/settings/route.ts` (lines 1–92)

```tsx
import { NextResponse } from "next/server";
import { createClient as createSupabaseServerClient } from "@/lib/supabase/server";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

export async function GET() {
  try {
    const supabase = await createSupabaseServerClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return NextResponse.json({ error: "Authentication required." }, { status: 401 });

    const { data } = await supabase.from("ai_settings").select("key, value");

    const settings: Record<string, string> = {};
    for (const row of data ?? []) {
      settings[row.key] = row.value;
    }

    return NextResponse.json({ settings });
  } catch (error) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function POST(request: Request) {
  const supabase = await createSupabaseServerClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) return NextResponse.json({ error: "Unauthenticated." }, { status: 401 });

  const body = await request.json();
  const { key, value } = body;

  // Upsert to Supabase (write operation)
  const { error } = await supabase.from("ai_settings").upsert(
    { key, value: value.trim(), updated_at: new Date().toISOString() },
    { onConflict: "key" }
  );

  if (error) throw error;
  return NextResponse.json({ ok: true });
}
```

